/*
  Core design system extracted and adapted from the reference layout.
  - Clean, minimalist, content focused
  - Light chrome, dark cybersecurity hero
  - Flat UI, very subtle borders, no heavy shadows
*/

:root {
  /* Brand and layout colors */
  --color-primary-bg: #0b0e12;          /* Dark hero background (from header image) */
  --color-primary-text: #ffffff;        /* Hero text on dark background */

  --color-page-bg: #f5f6f8;             /* Overall page background */
  --color-surface: #ffffff;             /* Card / content background */

  --color-border-subtle: #e5e5e5;       /* Light dividers */
  --color-border-soft: #dfe3e8;         /* Slightly stronger divider */

  --color-text-main: #555555;           /* Body text */
  --color-text-muted: #777777;          /* Muted / secondary text */
  --color-text-heading: #333333;        /* Headings on light background */

  --color-accent: #337ab7;              /* Links and key accents */

  --color-success: #28a745;
  --color-error: #dc3545;
  --color-warning: #ffc107;
  --color-info: #17a2b8;

  /* Typography scale */
  --font-family-heading: 'Space Grotesk', Helvetica, sans-serif;
  --font-family-body: 'Source Sans 3', Arial, sans-serif;
  --font-family-code: 'Fira Code', monospace;

  --font-size-base: 16px;
  --font-size-small: 13px;
  --font-size-h1: 36px;
  --font-size-h2: 28px;
  --font-size-h3: 22px;

  --line-height-tight: 1.2;
  --line-height-normal: 1.5;
  --line-height-relaxed: 1.75;

  /* Spacing scale (8px base unit) */
  --space-xxs: 4px;
  --space-xs: 8px;
  --space-sm: 16px;
  --space-md: 24px;
  --space-lg: 32px;
  --space-xl: 48px;
  --space-xxl: 64px;

  /* Layout constraints */
  --layout-max-width: 1100px;
  --layout-side-padding: 16px;

  /* Misc */
  --radius-sm: 3px;
  --radius-md: 4px;
  --transition-fast: 150ms ease-out;
}

/* Global reset / base styles ------------------------------------------------ */

* {
  box-sizing: border-box;
}

html {
  font-size: 100%;
}

body {
  margin: 0;
  font-family: var(--font-family-body);
  font-size: var(--font-size-base);
  line-height: var(--line-height-normal);
  color: var(--color-text-main);
  background-color: var(--color-page-bg);
  -webkit-font-smoothing: antialiased;
}

img {
  max-width: 100%;
  display: block;
}

a {
  color: var(--color-accent);
  text-decoration: none;
  transition: color var(--transition-fast), text-decoration-color var(--transition-fast);
}

a:hover,
a:focus {
  text-decoration: underline;
}

h1, h2, h3, h4, h5, h6 {
  margin: 0 0 var(--space-xs);
  font-family: var(--font-family-heading);
  font-weight: 600;
  color: var(--color-text-heading);
}

h1 { font-size: var(--font-size-h1); line-height: var(--line-height-tight); }

h2 { font-size: var(--font-size-h2); line-height: var(--line-height-tight); }

h3 { font-size: var(--font-size-h3); line-height: var(--line-height-tight); }

p {
  margin: 0 0 var(--space-sm);
}

ul {
  margin: 0;
  padding: 0;
}

.container {
  max-width: var(--layout-max-width);
  margin-left: auto;
  margin-right: auto;
  padding-left: var(--layout-side-padding);
  padding-right: var(--layout-side-padding);
}

/* Header and navigation ----------------------------------------------------- */

.site-header {
  background-color: var(--color-surface);
  color: var(--color-text-main);
}

.top-nav {
  background-color: #ffffff;
  border-bottom: 1px solid var(--color-border-subtle);
}

.nav-container {
  display: flex;
  align-items: center;
  justify-content: space-between;
  min-height: 64px;
}

.brand {
  font-family: var(--font-family-heading);
  font-weight: 700;
  font-size: 20px;
  letter-spacing: 0.02em;
  color: #2f3b4a;
  margin-right: var(--space-lg);
}

.brand:hover,
.brand:focus {
  color: #223041;
  text-decoration: none;
}

.primary-nav ul {
  display: flex;
  align-items: center;
  gap: 24px;
  list-style: none;
}

.primary-nav a {
  font-size: 15px;
  font-weight: 500;
  color: #666666;
  text-decoration: none;
  padding-bottom: 4px;
  border-bottom: 2px solid transparent;
}

.primary-nav a:hover,
.primary-nav a:focus {
  color: var(--color-accent);
  border-bottom-color: var(--color-accent);
}

.primary-nav a[aria-current='page'] {
  color: var(--color-accent);
  border-bottom-color: var(--color-accent);
}

/* Hero banner --------------------------------------------------------------- */

.hero {
  background-color: var(--color-primary-bg);
  /* Dark, moody cybersecurity texture approximation */
  background-image:
    linear-gradient(135deg, rgba(11, 14, 18, 0.96), rgba(11, 14, 18, 0.9)),
    radial-gradient(circle at 20% 20%, rgba(255, 255, 255, 0.06), transparent 55%),
    radial-gradient(circle at 80% 60%, rgba(255, 255, 255, 0.04), transparent 55%);
  background-size: cover;
  background-position: center;
  color: var(--color-primary-text);
  padding-top: var(--space-xl);
  padding-bottom: var(--space-xxl);
  border-bottom: 1px solid rgba(229, 229, 229, 0.4);
}

.hero-content {
  /* Align hero text with main content column */
}

.hero-title {
  font-size: var(--font-size-h1);
  line-height: var(--line-height-tight);
  font-weight: 700;
  margin-bottom: var(--space-xs);
  color: var(--color-primary-text);
}

.hero-subtitle {
  margin: 0;
  font-size: 15px;
  font-weight: 400;
  color: rgba(255, 255, 255, 0.75);
}

/* Main content wrapper ------------------------------------------------------ */

.main-content {
  background-color: var(--color-surface);
  padding-top: var(--space-lg);
  padding-bottom: var(--space-xl);
}

/* Footer -------------------------------------------------------------------- */

.site-footer {
  border-top: 1px solid var(--color-border-subtle);
  background-color: var(--color-page-bg);
  padding-top: var(--space-md);
  padding-bottom: var(--space-lg);
  font-size: var(--font-size-small);
  color: var(--color-text-muted);
}

.footer-container {
  display: flex;
  flex-wrap: wrap;
  align-items: center;
  justify-content: space-between;
  gap: var(--space-sm);
}

.footer-nav ul {
  display: flex;
  flex-wrap: wrap;
  gap: 16px;
  list-style: none;
}

.footer-nav a {
  color: var(--color-text-muted);
}

.footer-nav a:hover,
.footer-nav a:focus {
  color: var(--color-accent);
}

.footer-meta {
  margin: 0;
}

/* Utility classes ----------------------------------------------------------- */

.text-muted {
  color: var(--color-text-muted);
}

.text-center {
  text-align: center;
}

.code {
  font-family: var(--font-family-code);
  font-size: 0.95em;
}

/* Form foundation (for future use, styled to match layout) ------------------ */

.form-group {
  margin-bottom: var(--space-md);
}

.form-label {
  display: block;
  margin-bottom: var(--space-xxs);
  font-size: var(--font-size-small);
  color: var(--color-text-muted);
}

.form-control {
  display: block;
  width: 100%;
  padding: 8px 10px;
  font-family: var(--font-family-body);
  font-size: var(--font-size-base);
  color: var(--color-text-main);
  background-color: #ffffff;
  border: 1px solid var(--color-border-subtle);
  border-radius: var(--radius-md);
}

.form-control:focus {
  outline: none;
  border-color: var(--color-accent);
}

.form-text {
  margin-top: 4px;
  font-size: var(--font-size-small);
  color: var(--color-text-muted);
}

.form-text.error {
  color: var(--color-error);
}

.form-text.success {
  color: var(--color-success);
}

/* Buttons (for future use, matching the flat style) ------------------------- */

.btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  padding: 8px 18px;
  border-radius: var(--radius-sm);
  border: 1px solid transparent;
  font-size: 14px;
  font-weight: 600;
  font-family: var(--font-family-body);
  letter-spacing: 0.03em;
  text-transform: uppercase;
  cursor: pointer;
  background: none;
  transition: background-color var(--transition-fast), color var(--transition-fast), border-color var(--transition-fast);
}

.btn-primary {
  background-color: var(--color-accent);
  border-color: var(--color-accent);
  color: #ffffff;
}

.btn-primary:hover,
.btn-primary:focus {
  background-color: #3c86c5;
  border-color: #3c86c5;
}

/* Responsive adjustments ---------------------------------------------------- */

@media (max-width: 864px) {
  .nav-container {
    flex-wrap: wrap;
    gap: var(--space-xs);
    padding-top: 8px;
    padding-bottom: 8px;
  }

  .primary-nav ul {
    flex-wrap: wrap;
    row-gap: 8px;
  }

  .hero {
    padding-top: var(--space-lg);
    padding-bottom: var(--space-xl);
  }
}

@media (max-width: 600px) {
  .hero-content {
    text-align: left;
  }

  .footer-container {
    flex-direction: column;
    align-items: flex-start;
  }
}
